def solve(n, paths):
    from collections import defaultdict
    content_map = defaultdict(list)
    for p in paths:
        parts = p.split()
        root = parts[0]
        for f in parts[1:]:
            idx = f.index('(')
            fname = f[:idx]
            content = f[idx+1:-1]
            full_path = root + '/' + fname
            content_map[content].append(full_path)
    result = []
    for files in content_map.values():
        if len(files) >= 2:
            result.append(' '.join(sorted(files)))
    return '\n'.join(sorted(result))

